export const etagMiddleware: MiddlewareHandler = async (c, next) => {
  await next()

  const res = c.res
  if (!res.body || res.headers.has('ETag')) return

  const body = await res.clone().arrayBuffer()
  const etag = createHash('sha256').update(Buffer.from(body)).digest('hex')

  res.headers.set('ETag', `"${etag}"`)

