function toRpn(tokens) {
  const output = [];
  const ops = [];
  const prec = { "+": 1, "-": 1, "*": 2, "/": 2 };

  for (const token of tokens) {
    if (/^\d/.test(token) || /^[A-Za-z_]/.test(token)) {
      output.push(token);
    } else if (token in prec) {
      while (ops.length && ops[ops.length - 1] in prec &&
