        output.push(ops.pop());
      }
      ops.push(token);
    } else if (token === "(") {
      ops.push(token);
    } else if (token === ")") {
      while (ops.length && ops[ops.length - 1] !== "(") {
        output.push(ops.pop());
      }
      if (ops.pop() !== "(") {
        throw new Error("Mismatched parentheses");
