import ast
import operator as op
import re


_TEMPLATE_RE = re.compile(r"^\s*\{\{(.*)\}\}\s*$", re.DOTALL)

_ALLOWED_BINOPS = {
    ast.Add: op.add,
    ast.Sub: op.sub,
    ast.Mult: op.mul,
    ast.Div: op.truediv,
    ast.FloorDiv: op.floordiv,
    ast.Mod: op.mod,
    ast.Pow: op.pow,
}

_ALLOWED_UNARYOPS = {
    ast.UAdd: op.pos,
    ast.USub: op.neg,
    ast.Not: op.not_,
}

_ALLOWED_CMPOPS = {
    ast.Eq: op.eq,
    ast.NotEq: op.ne,
    ast.Lt: op.lt,
    ast.LtE: op.le,
    ast.Gt: op.gt,
    ast.GtE: op.ge,
}

_ALLOWED_FUNCS = {
    "min": min,
    "max": max,
    "abs": abs,
    "round": round,
}


class FormulaEvaluationError(ValueError):
    pass


def evaluate_formula(template: str, context: dict):
    match = _TEMPLATE_RE.match(template)
    if not match:
        raise FormulaEvaluationError("Template must be wrapped like {{ ... }}")

    expr = match.group(1).strip()
    tree = ast.parse(expr, mode="eval")
    return _eval_node(tree.body, context)


def _eval_node(node, context):
    if isinstance(node, ast.Constant):
        return node.value

    if isinstance(node, ast.Name):
        if node.id in context:
            return context[node.id]
        if node.id in _ALLOWED_FUNCS:
            return _ALLOWED_FUNCS[node.id]
        raise FormulaEvaluationError(f"Unknown name: {node.id}")

    if isinstance(node, ast.Attribute):
        base = _eval_node(node.value, context)
        if isinstance(base, dict):
            if node.attr in base:
                return base[node.attr]
            raise FormulaEvaluationError(f"Missing field: {node.attr}")
        raise FormulaEvaluationError("Attribute access is only allowed on dict objects")

    if isinstance(node, ast.Subscript):
        base = _eval_node(node.value, context)
        key = _eval_node(node.slice, context)
        try:
            return base[key]
        except Exception as exc:
            raise FormulaEvaluationError(f"Invalid subscript access: {key}") from exc

    if isinstance(node, ast.BinOp):
        op_type = type(node.op)
        if op_type not in _ALLOWED_BINOPS:
            raise FormulaEvaluationError(f"Operator not allowed: {op_type.__name__}")
        return _ALLOWED_BINOPS[op_type](
            _eval_node(node.left, context),
            _eval_node(node.right, context),
        )

    if isinstance(node, ast.UnaryOp):
        op_type = type(node.op)
        if op_type not in _ALLOWED_UNARYOPS:
            raise FormulaEvaluationError(f"Unary operator not allowed: {op_type.__name__}")
        return _ALLOWED_UNARYOPS[op_type](_eval_node(node.operand, context))

    if isinstance(node, ast.BoolOp):
        if isinstance(node.op, ast.And):
            result = True
            for value in node.values:
                result = _eval_node(value, context)
                if not result:
                    return result
            return result
        if isinstance(node.op, ast.Or):
            for value in node.values:
                result = _eval_node(value, context)
                if result:
                    return result
            return result
        raise FormulaEvaluationError("Boolean operator not allowed")

    if isinstance(node, ast.Compare):
        left = _eval_node(node.left, context)
        for op_node, comparator in zip(node.ops, node.comparators):
            right = _eval_node(comparator, context)
            op_type = type(op_node)
            if op_type not in _ALLOWED_CMPOPS:
                raise FormulaEvaluationError(f"Comparison not allowed: {op_type.__name__}")
            if not _ALLOWED_CMPOPS[op_type](left, right):
                return False
            left = right
        return True

    if isinstance(node, ast.IfExp):
        return _eval_node(node.body, context) if _eval_node(node.test, context) else _eval_node(node.orelse, context)

    if isinstance(node, ast.Call):
        func = _eval_node(node.func, context)
        if func not in _ALLOWED_FUNCS.values():
            raise FormulaEvaluationError("Function not allowed")
        args = [_eval_node(arg, context) for arg in node.args]
        return func(*args)

    raise FormulaEvaluationError(f"Unsupported expression: {type(node).__name__}")

